mapper.select:
SELECT ID, WORKPLACE_ID, AUTHOR_ID, TITLE, CONTENT, IS_PINNED, CREATED_AT, UPDATED_AT
FROM WORKPLACE_NOTICES
WHERE ID = #{id}

mapper.update:
UPDATE WORKPLACE_NOTICES
SET TITLE   = #{title},
    CONTENT = #{content}
WHERE ID = #{id}

UPDATE WORKPLACE_NOTICES
SET IS_PINNED = #{pinned}
WHERE ID = #{id}
